import{_ as o,c as e,o as a,a1 as r}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Ultrawork 모드: 모든 기능 활성화 | oh-my-opencode","description":"oh-my-opencode의 Ultrawork 모드를 배워 하나의 명령으로 모든 기능을 활성화하세요. 병렬 에이전트, 강제 완료, Category + Skills 시스템을 활성화합니다.","frontmatter":{"title":"Ultrawork 모드: 모든 기능 활성화 | oh-my-opencode","sidebarTitle":"Ultrawork 모드","subtitle":"Ultrawork 모드: 하나의 명령으로 모든 기능 활성화","description":"oh-my-opencode의 Ultrawork 모드를 배워 하나의 명령으로 모든 기능을 활성화하세요. 병렬 에이전트, 강제 완료, Category + Skills 시스템을 활성화합니다.","tags":["ultrawork","백그라운드 작업","에이전트 협업"],"prerequisite":["/ko/code-yeongyu/oh-my-opencode/start/installation/","/ko/code-yeongyu/oh-my-opencode/start/sisyphus-orchestrator/"],"order":30},"headers":[],"relativePath":"ko/code-yeongyu/oh-my-opencode/start/ultrawork-mode/index.md","filePath":"ko/code-yeongyu/oh-my-opencode/start/ultrawork-mode/index.md"}'),l={name:"ko/code-yeongyu/oh-my-opencode/start/ultrawork-mode/index.md"};function d(i,t,s,n,c,u){return a(),e("div",null,[...t[0]||(t[0]=[r(`<h1 id="ultrawork-모드-하나의-명령으로-모든-기능-활성화" tabindex="-1">Ultrawork 모드: 하나의 명령으로 모든 기능 활성화 <a class="header-anchor" href="#ultrawork-모드-하나의-명령으로-모든-기능-활성화" aria-label="Permalink to &quot;Ultrawork 모드: 하나의 명령으로 모든 기능 활성화&quot;">​</a></h1><h2 id="학습-내용" tabindex="-1">학습 내용 <a class="header-anchor" href="#학습-내용" aria-label="Permalink to &quot;학습 내용&quot;">​</a></h2><ul><li>하나의 명령으로 oh-my-opencode의 모든 고급 기능 활성화</li><li>여러 AI 에이전트가 실제 팀처럼 병렬로 작동하도록 설정</li><li>여러 에이전트와 백그라운드 작업을 수동으로 구성하는 번거로움 방지</li><li>Ultrawork 모드의 설계 철학과 모범 사례 이해</li></ul><h2 id="현재-겪고-있는-문제" tabindex="-1">현재 겪고 있는 문제 <a class="header-anchor" href="#현재-겪고-있는-문제" aria-label="Permalink to &quot;현재 겪고 있는 문제&quot;">​</a></h2><p>개발 중에 다음 상황에 직면했을 수 있습니다:</p><ul><li><strong>너무 많은 기능, 사용법을 모름</strong>: 10개의 전문 에이전트, 백그라운드 작업, LSP 도구가 있지만 빠르게 활성화하는 방법을 모름</li><li><strong>수동 구성 필요</strong>: 모든 복잡한 작업마다 에이전트, 백그라운드 동시성 등 설정을 수동으로 지정해야 함</li><li><strong>비효율적인 에이전트 협업</strong>: 에이전트를 순차적으로 호출하여 시간과 비용 낭비</li><li><strong>작업이 중간에 멈춤</strong>: 에이전트가 작업을 완료할 충분한 동기와 제약이 없음</li></ul><p>이 모든 것이 oh-my-opencode의 진정한 힘을 발휘하는 데 방해가 되고 있습니다.</p><h2 id="핵심-개념" tabindex="-1">핵심 개념 <a class="header-anchor" href="#핵심-개념" aria-label="Permalink to &quot;핵심 개념&quot;">​</a></h2><p><strong>Ultrawork 모드</strong>는 oh-my-opencode의 &quot;원클릭 전체 활성화&quot; 메커니즘입니다.</p><div class="info custom-block"><p class="custom-block-title">Ultrawork 모드란?</p><p>Ultrawork 모드는 키워드로 트리거되는 특수 작업 모드입니다. 프롬프트에 <code>ultrawork</code> 또는 약어 <code>ulw</code>가 포함되면 시스템이 자동으로 모든 고급 기능을 활성화합니다: 병렬 백그라운드 작업, 깊은 탐색, 강제 완료, 다중 에이전트 협업 등.</p></div><h3 id="설계-철학" tabindex="-1">설계 철학 <a class="header-anchor" href="#설계-철학" aria-label="Permalink to &quot;설계 철학&quot;">​</a></h3><p>Ultrawork 모드는 다음 핵심 원칙을 기반으로 합니다 (<a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/docs/ultrawork-manifesto.md" target="_blank" rel="noreferrer">Ultrawork 선언문</a> 참조):</p><table tabindex="0"><thead><tr><th>원칙</th><th>설명</th></tr></thead><tbody><tr><td><strong>사람 개입은 실패 신호</strong></td><td>AI 출력을 지속적으로 수정해야 한다면 시스템 설계에 문제가 있다는 의미</td></tr><tr><td><strong>구별할 수 없는 코드</strong></td><td>AI가 작성한 코드는 시니어 엔지니어가 작성한 코드와 구별할 수 없어야 함</td></tr><tr><td><strong>인지 부하 최소화</strong></td><td>&quot;무엇을 할지&quot;만 말하면 에이전트가 &quot;어떻게 할지&quot;를 담당</td></tr><tr><td><strong>예측 가능하고 일관적이며 위임 가능</strong></td><td>에이전트는 컴파일러처럼 안정적이고 신뢰할 수 있어야 함</td></tr></tbody></table><h3 id="활성화-메커니즘" tabindex="-1">활성화 메커니즘 <a class="header-anchor" href="#활성화-메커니즘" aria-label="Permalink to &quot;활성화 메커니즘&quot;">​</a></h3><p>시스템이 <code>ultrawork</code> 또는 <code>ulw</code> 키워드를 감지하면:</p><ol><li><strong>최대 정밀도 모드 설정</strong>: <code>message.variant = &quot;max&quot;</code></li><li><strong>Toast 알림 표시</strong>: &quot;Ultrawork Mode Activated - Maximum precision engaged. All agents at your disposal.&quot;</li><li><strong>완전한 지침 주입</strong>: 에이전트에 200줄 이상의 ULTRAWORK 지침 주입: <ul><li>구현 시작 전 100% 확신 요구</li><li>백그라운드 작업 병렬 사용 요구</li><li>Category + Skills 시스템 강제 사용</li><li>완료 검증 강제 (TDD 워크플로우)</li><li>&quot;할 수 없음&quot;이라는 변명 금지</li></ul></li></ol><h2 id="실습" tabindex="-1">실습 <a class="header-anchor" href="#실습" aria-label="Permalink to &quot;실습&quot;">​</a></h2><h3 id="_1단계-ultrawork-모드-트리거" tabindex="-1">1단계: Ultrawork 모드 트리거 <a class="header-anchor" href="#_1단계-ultrawork-모드-트리거" aria-label="Permalink to &quot;1단계: Ultrawork 모드 트리거&quot;">​</a></h3><p>OpenCode에서 <code>ultrawork</code> 또는 <code>ulw</code> 키워드가 포함된 프롬프트 입력:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ultrawork develop a REST API</span></span></code></pre></div><p>또는 더 간결하게:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ulw add user authentication</span></span></code></pre></div><p><strong>다음을 확인해야 합니다</strong>:</p><ul><li>인터페이스에 Toast 알림 팝업: &quot;Ultrawork Mode Activated&quot;</li><li>에이전트 응답이 &quot;ULTRAWORK MODE ENABLED!&quot;로 시작</li></ul><h3 id="_2단계-에이전트-동작-변화-관찰" tabindex="-1">2단계: 에이전트 동작 변화 관찰 <a class="header-anchor" href="#_2단계-에이전트-동작-변화-관찰" aria-label="Permalink to &quot;2단계: 에이전트 동작 변화 관찰&quot;">​</a></h3><p>Ultrawork 모드 활성화 후 에이전트는 다음을 수행합니다:</p><ol><li><p><strong>코드베이스 병렬 탐색</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>delegate_task(agent=&quot;explore&quot;, prompt=&quot;find existing API patterns&quot;, background=true)</span></span>
<span class="line"><span>delegate_task(agent=&quot;explore&quot;, prompt=&quot;find test infrastructure&quot;, background=true)</span></span>
<span class="line"><span>delegate_task(agent=&quot;librarian&quot;, prompt=&quot;find authentication best practices&quot;, background=true)</span></span></code></pre></div></li><li><p><strong>Plan 에이전트 호출하여 작업 계획 생성</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>delegate_task(subagent_type=&quot;plan&quot;, prompt=&quot;create detailed plan based on gathered context&quot;)</span></span></code></pre></div></li><li><p><strong>Category + Skills 사용하여 작업 실행</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>delegate_task(category=&quot;visual-engineering&quot;, load_skills=[&quot;frontend-ui-ux&quot;, &quot;playwright&quot;], ...)</span></span></code></pre></div></li></ol><p><strong>다음을 확인해야 합니다</strong>:</p><ul><li>여러 백그라운드 작업이 동시에 실행</li><li>에이전트가 전문 에이전트(Oracle, Librarian, Explore)를 적극적으로 호출</li><li>완전한 테스트 계획과 작업 분해</li><li>작업이 100% 완료될 때까지 계속 실행</li></ul><h3 id="_3단계-작업-완료-검증" tabindex="-1">3단계: 작업 완료 검증 <a class="header-anchor" href="#_3단계-작업-완료-검증" aria-label="Permalink to &quot;3단계: 작업 완료 검증&quot;">​</a></h3><p>에이전트 완료 후 다음을 수행합니다:</p><ol><li><strong>검증 증거 표시</strong>: 실제 테스트 실행 출력, 수동 검증 설명</li><li><strong>모든 TODO 완료 확인</strong>: 조기 완료 선언하지 않음</li><li><strong>완료된 작업 요약</strong>: 수행한 작업과 이유 나열</li></ol><p><strong>다음을 확인해야 합니다</strong>:</p><ul><li>명확한 테스트 결과 (&quot;작동해야 함&quot;이 아님)</li><li>모든 문제 해결됨</li><li>미완료 TODO 목록 없음</li></ul><h2 id="체크포인트-✅" tabindex="-1">체크포인트 ✅ <a class="header-anchor" href="#체크포인트-✅" aria-label="Permalink to &quot;체크포인트 ✅&quot;">​</a></h2><p>위 단계 완료 후 다음을 확인:</p><ul><li>[ ] <code>ulw</code> 입력 후 Toast 알림 표시</li><li>[ ] 에이전트 응답이 &quot;ULTRAWORK MODE ENABLED!&quot;로 시작</li><li>[ ] 병렬 백그라운드 작업 실행 관찰</li><li>[ ] 에이전트가 Category + Skills 시스템 사용</li><li>[ ] 작업 완료 후 검증 증거 존재</li></ul><p>항목 실패 시 다음 확인:</p><ul><li>키워드 철자가 올바른지 (<code>ultrawork</code> 또는 <code>ulw</code>)</li><li>메인 세션에 있는지 (백그라운드 작업은 모드 트리거하지 않음)</li><li>구성 파일에서 관련 기능이 활성화되어 있는지</li></ul><h2 id="언제-이-기법을-사용할까" tabindex="-1">언제 이 기법을 사용할까 <a class="header-anchor" href="#언제-이-기법을-사용할까" aria-label="Permalink to &quot;언제 이 기법을 사용할까&quot;">​</a></h2><table tabindex="0"><thead><tr><th>시나리오</th><th>Ultrawork 사용</th><th>일반 모드</th></tr></thead><tbody><tr><td><strong>복잡한 새 기능</strong></td><td>✅ 권장 (다중 에이전트 협업 필요)</td><td>❌ 효율성 부족</td></tr><tr><td><strong>긴급 수정</strong></td><td>✅ 권장 (빠른 진단과 탐색 필요)</td><td>❌ 컨텍스트 누락 가능</td></tr><tr><td><strong>간단한 수정</strong></td><td>❌ 과도함 (자원 낭비)</td><td>✅ 더 적합</td></tr><tr><td><strong>빠른 아이디어 검증</strong></td><td>❌ 과도함</td><td>✅ 더 적합</td></tr></tbody></table><p><strong>경험칙</strong>:</p><ul><li>작업이 여러 모듈이나 시스템과 관련 → <code>ulw</code> 사용</li><li>코드베이스 깊은 연구 필요 → <code>ulw</code> 사용</li><li>여러 전문 에이전트 호출 필요 → <code>ulw</code> 사용</li><li>단일 파일 작은 변경 → <code>ulw</code> 불필요</li></ul><h2 id="일반적인-실수" tabindex="-1">일반적인 실수 <a class="header-anchor" href="#일반적인-실수" aria-label="Permalink to &quot;일반적인 실수&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">중요 참고사항</p><p><strong>1. 모든 프롬프트에 <code>ulw</code> 사용하지 마세요</strong></p><p>Ultrawork 모드는 많은 지침을 주입하므로 간단한 작업에는 과도합니다. 진정으로 다중 에이전트 협업, 병렬 탐색, 깊은 분석이 필요한 복잡한 작업에만 사용하세요.</p><p><strong>2. 백그라운드 작업은 Ultrawork 모드를 트리거하지 않습니다</strong></p><p>키워드 감지기는 백그라운드 세션을 건너뛰어 모드가 하위 에이전트에 잘못 주입되는 것을 방지합니다. Ultrawork 모드는 메인 세션에서만 작동합니다.</p><p><strong>3. Provider 구성이 올바른지 확인하세요</strong></p><p>Ultrawork 모드는 여러 AI 모델이 병렬로 작동하는 것에 의존합니다. 특정 Provider가 구성되지 않았거나 사용할 수 없는 경우 에이전트가 전문 에이전트를 호출할 수 없을 수 있습니다.</p></div><h2 id="수업-요약" tabindex="-1">수업 요약 <a class="header-anchor" href="#수업-요약" aria-label="Permalink to &quot;수업 요약&quot;">​</a></h2><p>Ultrawork 모드는 키워드 트리거를 통해 &quot;하나의 명령으로 모든 기능 활성화&quot;라는 설계 목표를 달성합니다:</p><ul><li><strong>사용 쉬움</strong>: <code>ulw</code> 입력만으로 활성화</li><li><strong>자동 협업</strong>: 에이전트가 자동으로 다른 에이전트를 호출하고 백그라운드 작업을 병렬로 실행</li><li><strong>강제 완료</strong>: 완전한 검증 메커니즘으로 100% 완료 보장</li><li><strong>제로 구성</strong>: 에이전트 우선순위, 동시성 제한 등 수동 설정 불필요</li></ul><p>기억하세요: Ultrawork 모드는 에이전트가 실제 팀처럼 작동하도록 설계되었습니다. 의도만 표현하면 에이전트가 실행을 담당합니다.</p><h2 id="다음-수업-미리보기" tabindex="-1">다음 수업 미리보기 <a class="header-anchor" href="#다음-수업-미리보기" aria-label="Permalink to &quot;다음 수업 미리보기&quot;">​</a></h2><blockquote><p>다음 수업에서 **<a href="./../../platforms/provider-setup/">Provider 구성</a>**을 배웁니다.</p><p>학습 내용:</p><ul><li>Anthropic, OpenAI, Google와 같은 여러 Provider 구성 방법</li><li>다중 모델 전략이 자동으로 저하되고 최적 모델을 선택하는 방법</li><li>Provider 연결 및 할당량 사용 테스트 방법</li></ul></blockquote><hr><h2 id="부록-소스-코드-참조" tabindex="-1">부록: 소스 코드 참조 <a class="header-anchor" href="#부록-소스-코드-참조" aria-label="Permalink to &quot;부록: 소스 코드 참조&quot;">​</a></h2><details><summary><strong>소스 코드 위치 펼치기</strong></summary><blockquote><p>마지막 업데이트: 2026-01-26</p></blockquote><table tabindex="0"><thead><tr><th>기능</th><th>파일 경로</th><th>줄 번호</th></tr></thead><tbody><tr><td>Ultrawork 설계 철학</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/docs/ultrawork-manifesto.md" target="_blank" rel="noreferrer"><code>docs/ultrawork-manifesto.md</code></a></td><td>1-198</td></tr><tr><td>키워드 감지기 Hook</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/hooks/keyword-detector/index.ts" target="_blank" rel="noreferrer"><code>src/hooks/keyword-detector/index.ts</code></a></td><td>12-100</td></tr><tr><td>ULTRAWORK 지침 템플릿</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/hooks/keyword-detector/constants.ts" target="_blank" rel="noreferrer"><code>src/hooks/keyword-detector/constants.ts</code></a></td><td>54-280</td></tr><tr><td>키워드 감지 로직</td><td><a href="https://github.com/code-yeongyu/oh-my-opencode/blob/main/src/hooks/keyword-detector/detector.ts" target="_blank" rel="noreferrer"><code>src/hooks/keyword-detector/detector.ts</code></a></td><td>26-53</td></tr></tbody></table><p><strong>핵심 상수</strong>:</p><ul><li><code>KEYWORD_DETECTORS</code>: 키워드 감지기 구성, 세 가지 모드 포함: ultrawork, search, analyze</li><li><code>CODE_BLOCK_PATTERN</code>: 코드 블록 정규식 패턴, 코드 블록 내 키워드 필터링에 사용</li><li><code>INLINE_CODE_PATTERN</code>: 인라인 코드 정규식 패턴, 인라인 코드 내 키워드 필터링에 사용</li></ul><p><strong>핵심 함수</strong>:</p><ul><li><code>createKeywordDetectorHook()</code>: 키워드 감지기 Hook 생성, UserPromptSubmit 이벤트 수신</li><li><code>detectKeywordsWithType()</code>: 텍스트에서 키워드 감지 및 유형 반환 (ultrawork/search/analyze)</li><li><code>getUltraworkMessage()</code>: 완전한 ULTRAWORK 모드 지침 생성 (에이전트 유형에 따라 Planner 또는 일반 모드 선택)</li><li><code>removeCodeBlocks()</code>: 코드 블록 제거하여 코드 블록 내 키워드 트리거 방지</li></ul><p><strong>비즈니스 규칙</strong>:</p><table tabindex="0"><thead><tr><th>규칙 ID</th><th>규칙 설명</th><th>태그</th></tr></thead><tbody><tr><td>BR-4.8.4-1</td><td>&quot;ultrawork&quot; 또는 &quot;ulw&quot; 감지 시 Ultrawork 모드 활성화</td><td>[Fact]</td></tr><tr><td>BR-4.8.4-2</td><td>Ultrawork 모드는 <code>message.variant = &quot;max&quot;</code> 설정</td><td>[Fact]</td></tr><tr><td>BR-4.8.4-3</td><td>Ultrawork 모드는 Toast 알림 표시: &quot;Ultrawork Mode Activated&quot;</td><td>[Fact]</td></tr><tr><td>BR-4.8.4-4</td><td>백그라운드 작업 세션은 키워드 감지 건너뛰어 모드 주입 방지</td><td>[Fact]</td></tr><tr><td>BR-4.8.4-5</td><td>비메인 세션은 ultrawork 키워드만 허용, 다른 모드 주입 차단</td><td>[Fact]</td></tr></tbody></table></details>`,54)])])}const g=o(l,[["render",d]]);export{h as __pageData,g as default};
